Write a Go test (package cache, runnable under -race) proving Cache is safe under concurrent Set/Get.
```go
package cache
// func NewCache() *Cache
// func (c *Cache) Set(k, v string)
// func (c *Cache) Get(k string) string
```

response:
```go
package cache

import (
	"strconv"
	"sync"
	"testing"
)

func TestCacheConcurrent(t *testing.T) {
	c := NewCache()
	var wg sync.WaitGroup
	for i := 0; i < 50; i++ {
		wg.Add(2)
		go func(n int) { defer wg.Done(); c.Set(strconv.Itoa(n), "v") }(i)
		go func(n int) { defer wg.Done(); _ = c.Get(strconv.Itoa(n)) }(i)
	}
	wg.Wait()
	if c.Get("1") != "" && c.Get("1") != "v" {
		t.Fatalf("unexpected value %q", c.Get("1"))
	}
}
```

